import React from 'react';
import './jobposting.css';
import Sidebar from "../../Components/Layouts/DashboardLayout/Sidebar";
import HeaderDashboard from "../../Components/Layouts/DashboardLayout/HeaderDashboard";
import Alpha from "../../assets/images/DashboardImgs/alpha.png";
import Beta from "../../assets/images/DashboardImgs/Beta.png";
import Eye from "../../assets/images/DashboardImgs/eye.png";
import Edit from "../../assets/images/DashboardImgs/edit.png";
import Clip2 from "../../assets/images/DashboardImgs/clipboard-list2.png";
import PostIcon from "../../assets/images/DashboardImgs/post-icon.png";
import Search from "../../assets/images/DashboardImgs/search.png";
import Clip1 from "../../assets/images/DashboardImgs/clipboard-list1.png";
import { Link } from "react-router-dom";
import Settings from "../../assets/images/DashboardImgs/profile.png";
import PostedJobLists from './PostedJobLists';
import ApiRequest from '../../Services/ApiRequest';
import { RouteGuard } from '../../Services/RouteGuard';
import swal from 'sweetalert';
import { X } from "react-bootstrap-icons";
import store from '../../app/store';



class JobPosting extends React.Component {
    state = {
        jobLists: [],
        postCount: 0,
        selected: [],
        allSelect: false,
        active: false,
        inActive: false,
        featured: false,
        search: '',
        sort: '',
        searchInput: false


    }
    async componentDidMount() {
        RouteGuard('JobPosting')
        const getJobs = await ApiRequest.getRequest('/getAllJobs');
        console.log(getJobs);
        const response = await ApiRequest.getRequest('/jobPost');
        if (response && response.status === 200) {
            this.setState({
                jobLists: response.data.jobLists,
                postCount: response.data.jobLists.data.length
            })
        }
    }
    searchShow = () => {
        this.setState({
            searchInput: !this.state.searchInput
        })
    }
    searchForm = (event) => {
        event.preventDefault();
        this.filterJobByStatus();
    }
    onChangeFilterVal = (event) => {
        const { name, value } = event.target;
        this.setState({
            [name]: value
        }, () => {
            this.filterJobByStatus();
        })
    }
    onChangeJobStatus = (val) => {
        const btn = ['active', 'inActive', 'featured']
        this.setState({
            [val]: !this.state[val]
        })
        btn.map((key) => {
            if (key !== val) {
                this.setState({
                    [key]: false
                }, () => {
                    this.filterJobByStatus();
                })
            }
        })

    }
    filterJobByStatus = async () => {
        const { active, inActive, featured, sort, search } = this.state;
        const response = await ApiRequest.postRequest('/postSearch', { active, inActive, featured, sort, search })
        if (response && response.status === 200) {
            this.setState({
                jobLists: response.data.jobLists,
                postCount: response.data.jobLists.data.length
            })
        }
    }
    clearFilter = () => {
        this.setState({
            active: '',
            inActive: '',
            featured: '',
            sort: '',
            search: '',
        }, () => this.filterJobByStatus())
    }
    getPostByPage = async (pageNumber = 1) => {
        const response = await ApiRequest.getRequest(`/jobPost?page=${pageNumber}`)
        if (response && response.status === 200 && response.data.jobLists) {

            this.setState({
                jobLists: response.data.jobLists,
                postCount: response.data.jobLists.data.length
            });
        }
    }
    selectAllPosts = () => {
        if (this.state.jobLists && this.state.jobLists.data.length > 0) {
            let arr = [];
            this.state.jobLists.data.map((el, index) => {
                arr.push(index);
            })
            this.setState({
                selected: arr,
                allSelect: !this.state.allSelect
            }, () => {
                if (!this.state.allSelect) {
                    this.setState({
                        selected: []
                    })
                }
            })
        }
    }
    deselectAll = () => {
        this.setState({
            allSelect: false,
            selected: []
        })
    }
    selectPost = (index, event) => {
        console.log(index);
        let selectedItem = this.state.selected
        let key = selectedItem.findIndex(x => x == index);
        console.log(key)
        if (key !== -1) {
            selectedItem.splice(key, 1);
            this.setState({
                selected: selectedItem,
                allSelect: false
            }, console.log(this.state.selected))
        }
        if (key === -1) {
            selectedItem.push(index);
            this.setState({
                selected: selectedItem,
                allSelect: false
            }, console.log(this.state.selected))
        }
        // else {
        //     selectedItem.push(index);
        //     this.setState({
        //         selected: selectedItem,
        //         allSelect: false
        //     })
        // }
    }
    deleteSelectedPosts = async () => {
        let arr = [];
        if (this.state.selected.length > 0) {
            swal("Are you sure you want to do this?", {
                buttons: {
                    cancel: "Cancel",
                    Delete: {
                        value: true,
                        className: "swal-button--confirm swal-button--danger"
                    },
                },
                dangerMode: true,
            })
                .then(async (value) => {
                    if (value) {
                        this.state.selected.map(el => {
                            let id = this.state.jobLists.data[el].id;
                            arr.push(id);
                        })
                        const response = await ApiRequest.postRequest('/multiplePostDelete', { ids: arr });
                        if (response && response.status === 200) {
                            this.componentDidMount();
                        }
                    }
                });
        } else {
            swal("Please select at least one Job Post!");
        }
    }

    render() {
        return (
            <div className="container-fluid dashboard-body-bg p-0">
                <div className='dashboard'>
                    <Sidebar />
                    <div className='dashboard-app'>
                        <HeaderDashboard />
                        <div className='container-fluid jobPostingWrap'>

                            <div className="row mar-width-0 jobPostingFilterWrap">
                                <div className="row mar-width-0 jobPostingFilterWrapInner1">

                                    <div className="row mar-width-0 p-0 border-bottom pt-2 pb-2">
                                        <div className="col-md-3">
                                            <li className={`nav-item dropdown user-dropdown d-inline-block ${this.state.active || this.state.featured ? 'st-active' : ''}`}>
                                                <Link to="#" className="nav-link dropdown-toggle"
                                                    id="navbarDropdownMenuLink" role="button" data-bs-toggle="dropdown"
                                                    aria-expanded="false">
                                                    Active and Featured jobs
                                                </Link>
                                                <ul className="dropdown-menu shadow-sm"
                                                    aria-labelledby="navbarDropdownMenuLink">
                                                    <li><Link to="#" className={`dropdown-item ${this.state.active ? 'active' : ''}`} onClick={() => this.onChangeJobStatus('active')} >Active</Link></li>
                                                    <li><Link to="#" className={`dropdown-item ${this.state.featured ? 'active' : ''}`} onClick={() => this.onChangeJobStatus('featured')} >Featured</Link></li>
                                                </ul>
                                            </li>
                                        </div>
                                        <div className="col-md-3">
                                            <li className={`nav-item dropdown user-dropdown d-inline-block ${this.state.inActive ? 'st-active' : ''}`}>
                                                <Link to="" className="nav-link dropdown-toggle"
                                                    id="navbarDropdownMenuLink" role="button" data-bs-toggle="dropdown"
                                                    aria-expanded="false">
                                                    Closed Jobs
                                                </Link>
                                                <ul className="dropdown-menu shadow-sm"
                                                    aria-labelledby="navbarDropdownMenuLink">
                                                    <li><Link to="#" className={`dropdown-item ${this.state.inActive ? 'active' : ''}`} onClick={() => this.onChangeJobStatus('inActive')} >Inactive</Link></li>
                                                </ul>
                                            </li>
                                        </div>
                                        <div className="col-md-3">
                                            <button className="btn btn-post" onClick={() => { this.clearFilter() }}>Clear filter</button>
                                        </div>
                                        <div className="col-md-3">
                                            <select className="form-select" aria-label="Default select example" onChange={this.onChangeFilterVal} name="sort" value={this.state.sort}>
                                                <option selected>Sort by: All Jobs</option>
                                                <option value="ASC">ASC</option>
                                                <option value="DESC">DESC</option>
                                            </select>
                                        </div>
                                    </div>

                                    <div className="row mar-width-0 p-0 pt-2 pb-2 filter-2">
                                        <div className="col-md-3 align-self-center">
                                            <label className="custom-control fill-checkbox">
                                                <input type="checkbox" className="fill-control-input" onChange={this.selectAllPosts} checked={this.state.allSelect} />
                                                <span className="fill-control-indicator"></span>
                                                <span>Allow Jobs Selected</span>
                                            </label>
                                        </div>
                                        <div className="col-md-4 align-self-center">
                                            <Link to="#" className="deselect" onClick={this.deselectAll}>Deselect All</Link>
                                            <Link to="#" className="delete-link" onClick={this.deleteSelectedPosts}>Delete</Link>
                                        </div>
                                        <div className="col-md-5 text-right search">
                                            <form onSubmit={this.searchForm} className="searchForm">
                                                <div className="form-group text-left position-relative">
                                                    <input type="search" className={`form-control searchInput ${this.state.searchInput ? 'show' : ''}`} onChange={this.onChangeFilterVal} name="search" value={this.state.search} />
                                                    <X className={`closeSearchIcon ${this.state.searchInput ? '' : 'd-none'}`} color="#1A8FFF" onClick={() => this.searchShow()} />
                                                </div>
                                            </form>
                                            <img src={Search} className={`searchIcon cursor-pointer ${this.state.searchInput ? 'd-none' : ''}`} onClick={() => this.searchShow()} alt="" />

                                            <Link to="/PostJob" className="btn btn-post"> <img src={PostIcon} alt="" /> Post a Job</Link>
                                        </div>
                                    </div>
                                </div>

                                <PostedJobLists className="row mar-width-0 dashboardSectionTwo p-0" jobLists={this.state.jobLists} pageHandler={this.getPostByPage} selectPost={this.selectPost} selected={this.state.selected} pagination={true} checkBox={true} />
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        )
    }
}

export default JobPosting;

