import React from 'react';
import {Link} from "react-router-dom";
import DLogo from "../../../assets/images/DashboardImgs/dashboard-logo.png"
import CLipList from "../../../assets/images/DashboardImgs/clipboard-list.png";
import Group from "../../../assets/images/DashboardImgs/Group.png";
import Bill from "../../../assets/images/DashboardImgs/bill.png";
import Setting from "../../../assets/images/DashboardImgs/setting.png";
import DashB from "../../../assets/images/DashboardImgs/dashb.png";
import CLip from "../../../assets/images/DashboardImgs/clipboard.png";
import history from '../../../Utils/history';

class Sidebar extends React.Component {
    render() {
        const pathName = history.location.pathname;
        return (
            <div className="dashboard-nav">
                <header>
                    <Link to="#" className="brand-logo">
                        <img src={DLogo} className="d-logo" alt="" />
                    </Link>
                </header>
                <nav className="dashboard-nav-list">
                    <Link to="/Dashboard" className={`dashboard-nav-item ${pathName === '/Dashboard'?'active':""}`}>
                        <img src={DashB} className="sidebar-icon" alt="" />  Dashboard
                    </Link>
                    <Link to="/JobPosting" className={`dashboard-nav-item ${pathName === '/JobPosting'?'active':""}`}>
                        <img src={CLipList} className="sidebar-icon" alt="" /> Job Posting
                    </Link>
                    <Link to="/Applicants" className={`dashboard-nav-item ${pathName === '/Applicants'?'active':""}`}>
                        <img src={CLip} className="sidebar-icon" alt="" />  Applicants
                    </Link>
                    <Link to="#" className={`dashboard-nav-item ${pathName === '/Team'?'active':""}`}>
                        <img src={Group} className="sidebar-icon" alt="" /> Team
                    </Link>
                    <Link to="#" className={`dashboard-nav-item ${pathName === '/Billing'?'active':""}`}>
                        <img src={Bill} className="sidebar-icon" alt="" />  Billing
                    </Link>
                    <Link to="#" className={`dashboard-nav-item ${pathName === '/Settings'?'active':""}`}>
                        <img src={Setting} className="sidebar-icon" alt="" /> Settings
                    </Link>
                </nav>
            </div>
        )
    }
}

export default Sidebar;